{
  "name": "Standard Invoice — A4",
  "document_type": "facility_invoice",
  "facility_ids": null,
  "is_default": false,
  "is_active": true,
  "page_setup": {
    "paper": "A4",
    "orientation": "portrait",
    "margins": { "top": 15, "right": 18, "bottom": 15, "left": 18 },
    "repeat_header": true
  },
  "layout": {
    "type": "section",
    "rows": 4,
    "cols": 1,
    "flow": false,
    "cells": [
      {
        "row": 1, "col": 1, "row_span": 1, "col_span": 1, "valign": "top",
        "child": {
          "type": "section", "rows": 1, "cols": 2, "flow": false,
          "cells": [
            { "row": 1, "col": 1, "child": { "type": "block", "block": "company_header", "config": { "show_logo": true, "fields": ["company.name", "company.tax_pin", "company.address", "company.phone", "company.email"] } } },
            { "row": 1, "col": 2, "child": { "type": "block", "block": "document_details", "config": { "heading_text": "Invoice", "fields": ["document.number", "document.issued_at", "document.due_at", "document.status"] } } }
          ]
        }
      },
      {
        "row": 2, "col": 1, "valign": "top",
        "child": {
          "type": "section", "rows": 1, "cols": 2, "flow": false,
          "cells": [
            { "row": 1, "col": 1, "child": { "type": "block", "block": "customer_details", "config": { "heading_text": "Billed to", "show_labels": true, "label_position": "left", "fields": ["customer.name", "customer.phone", "customer.tax_pin"], "field_labels": { "customer.tax_pin": "PIN Number" } } } },
            { "row": 1, "col": 2, "child": { "type": "block", "block": "qr_code", "config": { "source": "field", "field": "document.verify_url", "size_mm": 28, "caption": "Scan to verify", "align": "center" } } }
          ]
        }
      },
      {
        "row": 3, "col": 1, "valign": "top",
        "child": {
          "type": "section", "rows": 1, "cols": 1, "flow": true,
          "cells": [
            { "row": 1, "col": 1, "child": { "type": "block", "block": "line_items", "config": { "show_row_numbers": true, "zebra": false, "fields": ["items.description", "items.quantity", "items.unit_price", "items.total"] } } }
          ]
        }
      },
      {
        "row": 4, "col": 1, "valign": "top",
        "child": {
          "type": "section", "rows": 1, "cols": 2, "flow": false,
          "cells": [
            { "row": 1, "col": 1, "child": { "type": "block", "block": "signature", "config": { "label": "Authorised signature", "show_line": true } } },
            { "row": 1, "col": 2, "child": { "type": "block", "block": "totals", "config": { "fields": ["totals.subtotal", "totals.tax", "totals.total", "totals.balance"] } } }
          ]
        }
      }
    ]
  }
}
